import { generateObject } from "ai";
import {
  extractionResultSchema,
  type ExtractionPromptOutput,
} from "./schema";
import { buildExtractionSystemPrompt } from "./prompt";
import type { ExtractionGraphContextRow, MessageContextRow } from "./types";
import { elapsedMs, logError, logInfo } from "../http/observability";

export async function extractStructuredGraph(input: {
  extractionModel: any;
  conversationHistory: MessageContextRow[];
  currentMessage?: MessageContextRow;
  graphContext: ExtractionGraphContextRow[];
  sourceText: string;
  onboarding: boolean;
  heading?: string;
  workspaceName?: string;
  projectNames?: string[];
}): Promise<ExtractionPromptOutput> {
  const startedAt = performance.now();
  logInfo("extraction.generate.started", "Structured extraction started", {
    onboarding: input.onboarding,
    hasHeading: input.heading !== undefined,
    contextMessageCount: input.conversationHistory.length,
    hasCurrentMessage: input.currentMessage !== undefined,
    graphContextCount: input.graphContext.length,
    sourceLength: input.sourceText.length,
  });

  try {
    const extractionOutput = await generateObject({
      model: input.extractionModel,
      schema: extractionResultSchema,
      temperature: 0.1,
      system: buildExtractionSystemPrompt({ onboarding: input.onboarding }),
      prompt: [
        "Conversation history (reference resolution only):",
        formatExtractionConversationHistory(input.conversationHistory),
        "",
        "Current message (extract only from this text when message metadata exists):",
        formatExtractionCurrentMessage(input.currentMessage, input.sourceText),
        "",
        "Resolved-from lineage constraints:",
        formatResolvedFromConstraints(input.currentMessage, input.conversationHistory),
        "",
        "Existing graph context (semantic index of prior extracted entities):",
        formatExtractionGraphContext(input.graphContext),
        "",
        "Workspace scope:",
        formatWorkspaceScope(input.workspaceName, input.projectNames),
        input.heading ? `Section heading: ${input.heading}` : "",
        "",
        "Current source text:",
        input.sourceText,
      ]
        .filter((line) => line.length > 0)
        .join("\n"),
    });

    const output = extractionOutput.object as ExtractionPromptOutput;
    logInfo("extraction.generate.completed", "Structured extraction completed", {
      onboarding: input.onboarding,
      entityCount: output.entities.length,
      relationshipCount: output.relationships.length,
      toolCount: output.tools.length,
      durationMs: elapsedMs(startedAt),
    });

    return output;
  } catch (error) {
    logError("extraction.generate.failed", "Structured extraction failed", error, {
      onboarding: input.onboarding,
      durationMs: elapsedMs(startedAt),
    });
    throw error;
  }
}

function formatExtractionConversationHistory(rows: MessageContextRow[]): string {
  if (rows.length === 0) {
    return "(no prior messages)";
  }

  return rows.map((row) => `[message:${row.id.id as string}] ${row.role.toUpperCase()}: ${row.text}`).join("\n");
}

function formatExtractionCurrentMessage(currentMessage: MessageContextRow | undefined, sourceText: string): string {
  if (!currentMessage) {
    return `(no message metadata; source text: ${sourceText})`;
  }

  return `[message:${currentMessage.id.id as string}] ${currentMessage.role.toUpperCase()}: ${currentMessage.text}`;
}

function formatExtractionGraphContext(rows: ExtractionGraphContextRow[]): string {
  if (rows.length === 0) {
    return "(no prior extracted entities)";
  }

  return rows
    .map((row) => {
      const table = row.id.tb;
      return `[entity:${table}:${row.id.id as string}] ${row.kind}: ${row.text} (confidence ${row.confidence.toFixed(2)}, source message ${row.sourceMessage.id as string})`;
    })
    .join("\n");
}

function formatWorkspaceScope(workspaceName?: string, projectNames?: string[]): string {
  if (!workspaceName) {
    return "(no workspace context)";
  }

  const lines = [`Workspace: "${workspaceName}"`];
  if (projectNames && projectNames.length > 0) {
    lines.push(`Existing projects: ${projectNames.map((name) => `"${name}"`).join(", ")}`);
  } else {
    lines.push("Existing projects: none");
  }

  return lines.join("\n");
}

function formatResolvedFromConstraints(
  currentMessage: MessageContextRow | undefined,
  conversationHistory: MessageContextRow[],
): string {
  if (!currentMessage) {
    return "Current message id unavailable; omit resolvedFromMessageId.";
  }

  const currentMessageId = currentMessage.id.id as string;
  if (conversationHistory.length === 0) {
    return [
      `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
      "Allowed resolvedFromMessageId values (history only): none",
      "Omit resolvedFromMessageId.",
    ].join("\n");
  }

  const historyMessageIds = conversationHistory.map((row) => row.id.id as string);
  return [
    `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
    `Allowed resolvedFromMessageId values (history only): ${historyMessageIds.join(", ")}`,
    "Use one of the allowed ids exactly, or omit resolvedFromMessageId.",
  ].join("\n");
}

import { embed } from "ai";
import { type RecordId, type Surreal } from "surrealdb";
import { elapsedMs, logError, logInfo, logWarn } from "../http/observability";
import type { GraphEntityRecord } from "./types";

export async function persistEmbeddings(input: {
  surreal: Surreal;
  embeddingModel: any;
  embeddingDimension: number;
  assistantMessageRecord: RecordId<"message", string>;
  assistantText: string;
  entities: Array<{ record: GraphEntityRecord; text: string }>;
}): Promise<void> {
  const startedAt = performance.now();
  logInfo("embedding.persist.started", "Embedding persistence started", {
    messageId: input.assistantMessageRecord.id as string,
    entityCount: input.entities.length,
  });

  try {
    const messageEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.assistantText);
    if (messageEmbedding) {
      await writeEmbedding({
        surreal: input.surreal,
        record: input.assistantMessageRecord,
        embedding: messageEmbedding,
        label: "assistant message",
      });
    }

    let embeddedEntityCount = 0;
    for (const entity of input.entities) {
      const entityEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, entity.text);
      if (!entityEmbedding) {
        continue;
      }

      await writeEmbedding({
        surreal: input.surreal,
        record: entity.record as RecordId<string, string>,
        embedding: entityEmbedding,
        label: `${entity.record.tb}:${entity.record.id as string}`,
      });
      embeddedEntityCount += 1;
    }

    logInfo("embedding.persist.completed", "Embedding persistence completed", {
      messageId: input.assistantMessageRecord.id as string,
      entityCount: input.entities.length,
      embeddedEntityCount,
      durationMs: elapsedMs(startedAt),
    });
  } catch (error) {
    logError("embedding.persist.failed", "Embedding persistence failed", error, {
      messageId: input.assistantMessageRecord.id as string,
      entityCount: input.entities.length,
      durationMs: elapsedMs(startedAt),
    });
    throw error;
  }
}

export async function createEmbedding(
  embeddingModel: any,
  embeddingDimension: number,
  value: string,
): Promise<number[] | undefined> {
  const normalized = value.trim();
  if (normalized.length === 0) {
    return undefined;
  }

  const result = await embed({
    model: embeddingModel,
    value: normalized,
  });

  if (result.embedding.length !== embeddingDimension) {
    logWarn("embedding.dimension_mismatch", "Skipping embedding write due to vector dimension mismatch", {
      actualDimension: result.embedding.length,
      configuredDimension: embeddingDimension,
    });
    return undefined;
  }

  return result.embedding;
}

async function writeEmbedding(input: {
  surreal: Surreal;
  record: RecordId<string, string>;
  embedding: number[];
  label: string;
}): Promise<void> {
  const [updateResult] = await input.surreal
    .query<[unknown]>(
      "UPDATE $record MERGE $patch RETURN AFTER;",
      {
        record: input.record,
        patch: { embedding: input.embedding },
      },
    )
    .collect<[unknown]>();

  if (queryResultHasRecordId(updateResult)) {
    return;
  }

  const verified = await verifyEmbeddingPresent(input.surreal, input.record, input.embedding.length);
  if (!verified) {
    throw new Error(`${input.label} embedding update verification failed`);
  }

  logWarn(
    "embedding.persist.unexpected_update_output",
    "embedding update returned no row but verification succeeded",
    { record: input.label },
  );
}

async function verifyEmbeddingPresent(
  surreal: Surreal,
  record: RecordId<string, string>,
  expectedDimension: number,
): Promise<boolean> {
  const [queryResult] = await surreal
    .query<[unknown]>("SELECT id, embedding FROM $record;", { record })
    .collect<[unknown]>();
  const row = extractRecordFromPayload(queryResult);
  if (!row || row.id === undefined) {
    return false;
  }

  const vectorLength = readVectorLength(row.embedding);
  return vectorLength === expectedDimension;
}

function queryResultHasRecordId(result: unknown): boolean {
  return flattenQueryResult(result).some((candidate) => {
    if (!candidate || typeof candidate !== "object" || !("id" in candidate)) {
      return false;
    }
    return (candidate as { id?: unknown }).id !== undefined;
  });
}

function extractRecordFromPayload(value: unknown):
  | { id?: unknown; embedding?: unknown }
  | undefined {
  const candidates = flattenQueryResult(value).filter((entry) => entry && typeof entry === "object");
  const withId = candidates.find((entry) => "id" in (entry as Record<string, unknown>));
  if (withId) {
    return withId as { id?: unknown; embedding?: unknown };
  }

  const first = candidates[0];
  return first ? (first as { id?: unknown; embedding?: unknown }) : undefined;
}

function flattenQueryResult(value: unknown): unknown[] {
  if (!Array.isArray(value)) {
    return [value];
  }

  const flattened: unknown[] = [];
  for (const entry of value) {
    if (Array.isArray(entry)) {
      flattened.push(...flattenQueryResult(entry));
      continue;
    }
    flattened.push(entry);
  }

  return flattened;
}

function readVectorLength(value: unknown): number | undefined {
  if (Array.isArray(value)) {
    return value.length;
  }

  if (ArrayBuffer.isView(value)) {
    const arrayLike = value as { length?: number };
    if (typeof arrayLike.length === "number") {
      return arrayLike.length;
    }
  }

  if (value && typeof value === "object" && Symbol.iterator in value) {
    const iterator = (value as { [Symbol.iterator]?: () => Iterator<unknown> })[Symbol.iterator];
    if (typeof iterator === "function") {
      return [...(value as Iterable<unknown>)].length;
    }
  }

  return undefined;
}

